    categoryColor: "#cba6f7",
    source:
      'import React from "react"\nimport { render, Box, Text, useApp, useInput, createTerm } from "../../src/index.js"\nimport { ExampleBanner, type ExampleMeta } from "../_banner.js"\n\nexport const meta: ExampleMeta = {\n  name: "Overflow",\n  description: \'overflow="hidden" content clipping demonstration\',\n  features: [\'overflow="hidden"\', "Box height"],\n}\n\nexport function OverflowApp() {\n  const { exit } = useApp()\n  useInput((input, key) => {\n    if (input === "q" || key.escape) exit()\n  })\n\n  return (\n    <Box flexDirection="column" padding={1}>\n      <Text color="yellow">Title</Text>\n\n      <Box borderStyle="single" borderColor="cyan" height={5} overflow="hidden">\n        <Box flexDirection="column" flexGrow={1}>\n          <Text>Line 1</Text>\n          <Text>Line 2</Text>\n          <Text>Line 3</Text>\n          <Text>Line 4</Text>\n          <Text>Line 5</Text>\n          <Text>Line 6 - should NOT appear</Text>\n          <Text>Line 7 - should NOT appear</Text>\n        </Box>\n      </Box>\n\n      <Text color="green">This should NOT be corrupted</Text>\n    </Box>\n  )\n}\n\nasync function main() {\n  using term = createTerm()\n  const { waitUntilExit } = await render(\n    <ExampleBanner meta={meta} controls="Esc/q quit">\n      <OverflowApp />\n    </ExampleBanner>,\n    term,\n  )\n  await waitUntilExit()\n}\n\nif (import.meta.main) {\n  main().catch(console.error)\n}\n',
    type: "example",
